   805→async function analyzeVideoInterviewResponse(question, transcription, frames, durationSeconds, keyPoints, options = {}) {
   806→  const audioData = options.audioData || null;
   807→  let finalTranscription = transcription;
   808→
   809→  // Step 1: If audio data available, try Whisper for more accurate transcription
   810→  let whisperResult = null;
   811→  if (audioData) {
   812→    try {
   813→      console.log('[ai] Transcribing audio with Whisper...');
   814→      whisperResult = await transcribeAudioWithWhisper(audioData, options);
   815→      if (whisperResult && whisperResult.text && whisperResult.text.trim().length > 20) {
   816→        finalTranscription = whisperResult.text;
   817→        console.log(`[ai] Whisper transcription: ${finalTranscription.length} chars (replaced browser transcription)`);
   818→      } else {
   819→        console.log('[ai] Whisper result too short, keeping browser transcription');
   820→      }
   821→    } catch (err) {
   822→      console.warn('[ai] Whisper failed, using browser transcription:', err.message);
   823→    }
   824→  }
   825→
   826→  // Step 2: Run all analyses in parallel — use allSettled so partial failures don't kill the whole pipeline
   827→  const analysisPromises = [
   828→    analyzeInterviewResponse(question, finalTranscription, keyPoints, options),
   829→    generateInterviewCoaching(question, finalTranscription, { score: 5, strengths: [], improvements: [] }, options),
   830→    analyzeVideoPresentation(frames, options)
   831→  ];
   832→
   833→  // Add voice quality analysis if we have audio
   834→  if (audioData) {
   835→    analysisPromises.push(analyzeVoiceQuality(finalTranscription, durationSeconds, options));
   836→  }
   837→
   838→  const settled = await Promise.allSettled(analysisPromises);
   839→
   840→  // Extract results with fallbacks for any failed analyses
   841→  const contentAnalysis = settled[0].status === 'fulfilled' ? settled[0].value : {
   842→    score: 5, strengths: ['Response provided'], improvements: ['AI analysis temporarily unavailable'],
   843→    covered_points: [], missed_points: [], detailed_feedback: 'Analysis could not be completed. Please try again.'
   844→  };
   845→  const contentCoaching = settled[1].status === 'fulfilled' ? settled[1].value : {
   846→    improved_response: '', specific_tips: ['Try again for detailed tips'], body_language_tips: [],
   847→    common_mistake: '', practice_prompt: ''
   848→  };
   849→  const videoAnalysis = settled[2].status === 'fulfilled' ? settled[2].value : {
   850→    eye_contact: { score: 5, feedback: 'Video analysis unavailable' },
   851→    facial_expressions: { score: 5, feedback: 'Video analysis unavailable' },
   852→    body_language: { score: 5, feedback: 'Video analysis unavailable' },
   853→    professional_appearance: { score: 5, feedback: 'Video analysis unavailable' },
   854→    overall_presentation: 5, summary: 'Video analysis temporarily unavailable.', timestamped_notes: []
   855→  };
   856→  const voiceAnalysis = (audioData && settled[3] && settled[3].status === 'fulfilled') ? settled[3].value : null;
   857→
   858→  // Log any failures for debugging
   859→  settled.forEach((s, i) => {
   860→    if (s.status === 'rejected') {
   861→      const names = ['contentAnalysis', 'contentCoaching', 'videoAnalysis', 'voiceAnalysis'];
   862→      console.error(`[video-analysis] ${names[i]} failed:`, s.reason?.message || s.reason);
   863→    }
   864→  });
   865→
   866→  // Algorithmic speech analysis
   867→  const speechAnalysis = analyzeSpeechPatterns(finalTranscription, durationSeconds);
   868→
   869→  // Calculate category scores
   870→  const contentScore = contentAnalysis.score || 5;
   871→  let communicationScore = speechAnalysis.communication_score || 5;
   872→  const presentationScore = videoAnalysis.overall_presentation || 5;
   873→
   874→  // If voice analysis available, blend its score into communication
   875→  if (voiceAnalysis && voiceAnalysis.overall_voice_score) {
   876→    // 60% algorithmic speech analysis, 40% AI voice quality
   877→    communicationScore = Math.round(
   878→      (communicationScore * 0.6 + voiceAnalysis.overall_voice_score * 0.4) * 10
   879→    ) / 10;
   880→    communicationScore = Math.max(1, Math.min(10, communicationScore));
   881→  }
   882→
   883→  // Weighted overall score
   884→  const overallScore = Math.round(
   885→    (contentScore * 0.45 + communicationScore * 0.25 + presentationScore * 0.30) * 10
   886→  ) / 10;
   887→
   888→  return {
   889→    overall_score: overallScore,
   890→
   891→    // Category breakdowns
   892→    content: {
   893→      score: contentScore,
   894→      strengths: contentAnalysis.strengths || [],
   895→      improvements: contentAnalysis.improvements || [],
   896→      covered_points: contentAnalysis.covered_points || [],
   897→      missed_points: contentAnalysis.missed_points || [],
   898→      detailed_feedback: contentAnalysis.detailed_feedback || '',
