                    {responseText.length >= 50 && <CheckCircle className="h-3.5 w-3.5 text-green-500" />}
                  </div>

                  <div className="flex gap-2 mt-3">
                    <Button variant="outline" onClick={() => setResponseMode('select')} className="flex-1">
