                              <ul className="space-y-1">
                                {coaching.communication.voice_analysis.voice_tips.map((tip: string, i: number) => (
                                  <li key={i} className="text-xs text-violet-700">{tip}</li>
                                ))}
                              </ul>
                            </div>
